import React, { useState, useEffect } from 'react';
import { useDailyOperationsContext } from './DailyOperationsContext';
import { DailyRecord, TripAssignment, DailyTrip, useAppDispatch } from './types';
import { handleSave } from './Reports';
import { setStatus } from './Reports'; // Assuming setStatus is exported from Reports.tsx
import { convertDateToBRFormat } from '../utils/dateUtils';

interface DailyOperationsProps {
  date: string;
}

const DailyOperations: React.FC<DailyOperationsProps> = ({ date }) => {
  const { dailyRecords, setDailyRecords, volume, trucks, assignments, trips,  onSaveRecord, setTrips } = useDailyOperationsContext();
  const dispatch = useAppDispatch();
  const [isSaving, setIsSaving] = useState(false);


  const record = dailyRecords?.find(record => record.date === date);

  const [localVolume, setLocalVolume] = useState(volume);
  const [localTrucks, setLocalTrucks] = useState(trucks);
  const [localAssignments, setLocalAssignments] = useState(assignments);

  useEffect(() => {
    setLocalVolume(volume);
  }, [volume]);

  useEffect(() => {
    setLocalTrucks(trucks);
  }, [trucks]);

  useEffect(() => {
    setLocalAssignments(assignments);
  }, [assignments]);

  useEffect(() => {
    if (record) {
      setLocalVolume(String(record.volume));
      setLocalTrucks(String(record.trucks));
      setLocalAssignments(record.assignments);
    }
  }, [dailyRecords, date, record]);


  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setLocalVolume(e.target.value);
  };

  const handleTrucksChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setLocalTrucks(e.target.value);
  };


  const handleAssignmentsChange = (updatedAssignment: TripAssignment) => {
    setLocalAssignments(prevAssignments => {
      const existingIndex = prevAssignments.findIndex(a => a.id === updatedAssignment.id);

      if (existingIndex !== -1) {
        // If the assignment already exists, update it
        const newAssignments = [...prevAssignments];
        newAssignments[existingIndex] = updatedAssignment;
        return newAssignments;
      } else {
        // If it doesn't exist, add it
        return [...prevAssignments, updatedAssignment];
      }
    });
  };

  const handleAddAssignment = () => {
    const newId = Math.max(...localAssignments.map(a => a.id), 0) + 1;
    const newAssignment = { id: newId, driver: '', licensePlate: '' };
    setLocalAssignments(prevAssignments => [...prevAssignments, newAssignment]);
  };


  const handleRemoveAssignment = (idToRemove: number) => {
    setLocalAssignments(prevAssignments => prevAssignments.filter(a => a.id !== idToRemove));
  };

  const toggleTripUnsealed = (tripId: number) => {
    setTrips((prevTrips) => {
      const newTrips = prevTrips.map((trip) => {
        if (trip.id === tripId) {
          return { ...trip, unsealed: !trip.unsealed, timestamp: convertDateToBRFormat(new Date()) };
        }
        return trip;
      });

      // Prepare the record for saving, including only non-empty trip IDs
      const recordToSave: DailyRecord = {
        id: date,
        date,
        volume: Number(localVolume) || 0, // Fallback to 0 if empty
        trucks: Number(localTrucks) || 0, // Fallback to 0 if empty
        assignments: localAssignments,
        trips: newTrips.filter(trip => trip.id !== -1), // Exclude trips with id -1 or empty
      };

      onSaveRecord(recordToSave);
      return newTrips;
    });
  };

  if (!dailyRecords) {
    return <div>Loading...</div>;
  }



